:root {
  --font-family: 'Open Sans', sans-serif;
  --font-weight-normal: 400;
  --font-weight-bold: 600;
  --font-size-body: 13px;
  --font-size-label: 13px;
  --font-size-input: 14px;
  --font-size-header: 22px;
  --font-size-subheader: 13px;

  /* Colores */
  --color-background: #f0f4ff;
  --color-card-bg: #ffffff;
  --color-card-border: #c8d8f5;
  --color-card-shadow: rgba(26, 79, 160, 0.07);
  --color-header: #0d2b6e;
  --color-label: #1a3a6b;
  --color-input-border: #c8d8f5;
  --color-input-text: #0d2b6e;
  --color-focus-border: #2d72d2;
  --color-submit-btn-bg: #2d72d2;
  --color-submit-btn-text: #ffffff;
  --color-error: #d63a3a;
  --color-required: #2d72d2;
  --color-header-subtext: #6b8ab5;
  --color-link: #2d72d2;

  /* Radios más modernos */
  --border-radius-card: 16px;
  --border-radius-input: 10px;
  --card-border-radius: 16px;

  /* Espaciado */
  --padding-container-top: 32px;
  --padding-card: 28px 24px;
  --card-padding: 28px 24px;
  --margin-bottom-card: 16px;
  --card-margin-bottom: 16px;
  --padding-form-input: 11px 14px;

  /* Dimensiones */
  --container-width: 448px;
  --submit-btn-height: 50px;
  --checkbox-size: 18px;

  --box-shadow-card: 0px 2px 16px 0px var(--color-card-shadow);
  --opacity-placeholder: 0.55;
}

