// Iteramos sobre todos los items recibidos
return items.map(item => {

  // 1. Obtenemos el valor de "Forma de Pago".
  // Usamos el operador ?. para evitar errores si 'output' no existe.
  const formaPago = item.json.output?.['Forma de Pago'];

  // 2. Definimos la lógica
  // Por defecto asignamos 10. Esto cubre el caso de que sea 1, null, undefined o vacío.
  let resultadoMedioPago = 10; 

  // Si el valor es explícitamente 2 (o "2" en texto), cambiamos el resultado a 1.
  if (formaPago == 2) {
    resultadoMedioPago = 1;
  }

  // 3. Asignamos el resultado a una nueva propiedad
  // Si tu estructura usa 'output', guardamos el resultado ahí mismo para mantener el orden.
  if (item.json.output) {
    item.json.output['Medio de Pago'] = resultadoMedioPago;
  } else {
    // Si no existe output, lo creamos o lo ponemos en la raíz
    item.json['Medio de Pago'] = resultadoMedioPago;
  }

  return item;
});

